@implementation NameAndIconViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    self.title = @"修改头像/昵称";

    // Load Data
    [self loadData];

    // Setup UI
//    [self setupNavigationBarAppearance];
    [self setupUI];

    // Update initial state
    [self updateSelectionState];
}

- (void)loadData {
    if (self.chatId) {
        NSArray<ChatItemModel *> *list = [ChatStorage loadChatList];
        for (ChatItemModel *item in list) {
            if ([item.chatId isEqualToString:self.chatId]) {
                self.chatItem = item;
                break;
            }
        }
    }

    // Defaults (Mock data for UI if model doesn't support these fields yet)
    self.selectedBgIndex = self.chatItem ? self.chatItem.bgIndex : 0;
    self.selectedColorIndex = self.chatItem ? self.chatItem.bubbleColorIndex : 0;

    if (!self.bgButtons) self.bgButtons = [NSMutableArray array];
    if (!self.colorButtons) self.colorButtons = [NSMutableArray array];
}

#pragma mark - 设置导航栏样式

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
}

- (void)viewWillDisappear:(BOOL)animated {
    [super viewWillDisappear:animated];
    if (@available(iOS 13.0, *)) {
        UINavigationBarAppearance *appearance = [[UINavigationBarAppearance alloc] init];
        [appearance configureWithOpaqueBackground];
        appearance.backgroundColor = [UIColor whiteColor];

        self.navigationController.navigationBar.standardAppearance = appearance;
        self.navigationController.navigationBar.scrollEdgeAppearance = appearance;
    } else {
        [self.navigationController.navigationBar setShadowImage:nil];
        [self.navigationController.navigationBar setBackgroundImage:nil forBarMetrics:UIBarMetricsDefault];
    }
}

#pragma mark - Setup UI

- (void)setupUI {
    self.view.backgroundColor = WHITE_COLOR;

    self.scrollView = [[UIScrollView alloc] init];
    self.scrollView.showsVerticalScrollIndicator = NO;
    self.scrollView.alwaysBounceVertical = YES;
    [self.view addSubview:self.scrollView];

    self.titleLabel = [[UILabel alloc] init];
    self.titleLabel.text = self.title;

    self.cancelButton = [[UIButton alloc] init];
    [self.cancelButton setTitle:@"取消" forState:UIControlStateNormal];
    [self.cancelButton addTarget:self action:@selector(handleBack) forControlEvents:UIControlEventTouchUpInside];
    [self.cancelButton setTitleColor:RGBA(153, 153, 153, 1) forState:UIControlStateNormal];

    self.completeButton = [[UIButton alloc] init];
    [self.completeButton setTitle:@"完成" forState:UIControlStateNormal];
    [self.completeButton setTitleColor:RGB(23, 183, 148) forState:UIControlStateNormal];
    [self.completeButton addTarget:self action:@selector(handleComplete) forControlEvents:UIControlEventTouchUpInside];
    [self.view addSubview:self.titleLabel];
    [self.view addSubview:self.cancelButton];
    [self.view addSubview:self.completeButton];

    self.contentView = [[UIView alloc] init];
    [self.scrollView addSubview:self.contentView];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop).offset(ZOOM(32));
        make.centerX.equalTo(self.view);
    }];

    [self.cancelButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.view).offset(ZOOM(16));
        make.centerY.equalTo(self.titleLabel);
    }];

    [self.completeButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.view).offset(ZOOM(-16));
        make.centerY.equalTo(self.titleLabel);
    }];

    [self.scrollView mas_makeConstraints:^(MASConstraintMaker *make) {
//        make.edges.equalTo(self.view);
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop).offset(ZOOM(65));
        make.left.right.bottom.equalTo(self.view);
    }];

    [self.contentView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.scrollView);
        make.width.equalTo(self.scrollView);
    }];

    UIView *lastView = nil;

    lastView = [self createSectionTitle:@"" topView:lastView topOffset:24];
    lastView = [self createProfilePictureSection:lastView];

    lastView = [self createSectionTitle:@"对方昵称" topView:lastView topOffset:24];
    lastView = [self createNameSection:lastView];

    [self.contentView mas_updateConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(lastView.mas_bottom).offset(40);
    }];
}

- (UIView *)createSectionTitle:(NSString *)title topView:(UIView *)topView topOffset:(CGFloat)offset {
    UILabel *label = [[UILabel alloc] init];
    label.text = title;
    label.font = [UIFont systemFontOfSize:ZOOM(16) weight:UIFontWeightMedium];
    label.textColor = RGB(51, 51, 51);
    [self.contentView addSubview:label];

    [label mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.contentView).offset(20);
        if (topView) {
            make.top.equalTo(topView.mas_bottom).offset(offset);
        } else {
            make.top.equalTo(self.contentView).offset(offset);
        }
    }];
    return label;
}

- (UIView *)createChatBackgroundSection:(UIView *)topView {
    CGFloat itemSize = 107; // Approx
    CGFloat spacing = 11;
    CGFloat horizontalPadding = 20; // 左右边距

    UIView *container = [[UIView alloc] init];
    [self.contentView addSubview:container];

    CGFloat containerHeight = itemSize * 2 + spacing;

    [container mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(topView.mas_bottom).offset(12);
        make.left.right.equalTo(self.contentView);
        make.height.mas_equalTo(containerHeight);
    }];

    NSArray *colors = @[RGBA(230, 230, 230, 1), RGBA(196, 207, 214, 1), RGBA(220, 231, 237, 1), RGBA(241, 236, 208, 1), RGBA(244, 227, 226, 1), RGBA(224, 234, 213, 1)];

    UIView *lastItemInRow1 = nil;
    UIView *lastItemInRow2 = nil;

    for (int i = 0; i < colors.count; i++) {
        UIButton *btn = [UIButton buttonWithType:UIButtonTypeCustom];
        btn.backgroundColor = colors[i];
        btn.layer.cornerRadius = 12;
        btn.tag = i;
        [btn addTarget:self action:@selector(bgButtonTapped:) forControlEvents:UIControlEventTouchUpInside];
        [container addSubview:btn];
        [self.bgButtons addObject:btn];

        [btn mas_makeConstraints:^(MASConstraintMaker *make) {
            make.width.height.mas_equalTo(itemSize);

            if (i < 3) {
                make.top.equalTo(container).offset(0);
                if (lastItemInRow1) {
                    make.left.equalTo(lastItemInRow1.mas_right).offset(spacing);
                } else {
                    make.left.equalTo(container).offset(horizontalPadding);
                }
            }

            else {
                make.top.equalTo(container).offset(itemSize + spacing);
                if (lastItemInRow2) {
                    make.left.equalTo(lastItemInRow2.mas_right).offset(spacing);
                } else {
                    make.left.equalTo(container).offset(horizontalPadding);
                }
            }
        }];

        // Add checkmark (hidden by default)
        UIImageView *check = [[UIImageView alloc] initWithImage:[UIImage systemImageNamed:@"checkmark.circle.fill"]];
        check.tintColor = [UIColor darkGrayColor]; // Or black
        if (i == 0) check.tintColor = [UIColor blackColor];

