    UIViewAnimationCurve curve = [info[UIKeyboardAnimationCurveUserInfoKey] integerValue];
    CGRect endFrame = [info[UIKeyboardFrameEndUserInfoKey] CGRectValue];
    CGRect keyboardFrameInView = [self.view convertRect:endFrame fromView:nil];
    CGFloat keyboardHeight = MAX(0.0, CGRectGetMaxY(self.view.bounds) - CGRectGetMinY(keyboardFrameInView));

    CGFloat desiredOverlap = ZOOM(22);
    CGFloat offsetDistance = MAX(0.0, keyboardHeight - desiredOverlap);
    [self.sendViewBottomConstraint setOffset:-offsetDistance];
    [UIView animateWithDuration:duration delay:0 options:(curve << 16) animations:^{
        [self.view layoutIfNeeded];
    } completion:nil];
    [self scrollToBottom];
}

