- (void)scrollToBottomAnimated:(BOOL)animated {
    if (self.messages.count == 0) return;
    NSInteger lastRow = self.messages.count - 1;
    NSInteger numberOfRows = [self.tableView numberOfRowsInSection:0];
    if (lastRow >= 0 && lastRow < numberOfRows) {
        NSIndexPath *last = [NSIndexPath indexPathForRow:lastRow inSection:0];
        [self.tableView scrollToRowAtIndexPath:last atScrollPosition:UITableViewScrollPositionBottom animated:animated];
    } else {
        CGFloat offsetY = self.tableView.contentSize.height - self.tableView.bounds.size.height + self.tableView.contentInset.bottom;
        CGPoint bottomOffset = CGPointMake(0, MAX(-self.tableView.contentInset.top, offsetY));
        [self.tableView setContentOffset:bottomOffset animated:animated];
    }
}


