    [_chatTableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.messageView.mas_top);
    }];

    // 设置messageView约束
    [_messageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(88));
        make.width.mas_equalTo(self.view.width);
    }];

}

//Message初始化
- (void)setupMessages {
    [self.chatTableView registerClass:[ChatMessageCell class] forCellReuseIdentifier:@"ChatMessageCell"]; // 注册消息单元格类
    self.messages = [MessageModel messagesForAccount:self.aiID];
    if (self.messages.count == 0) {
        [self.messages addObject:[[MessageModel alloc] initWithText:self.options time:[NSDate date] type:MessageTypeReceived accountId:self.aiID cellHeight:[self getStringWidthToCellHeight:self.options] context:@"[]" Done:YES]];
    }
    // 获取最后一个消息，判断接收ai消息时是否被中断，最后一次对话无法完成，所以在这里删除
    MessageModel *lastMessage = [self.messages lastObject];
    if (!lastMessage.done) {
        // 删除最后两个元素
        [self.messages removeLastObject];
        [self.messages removeLastObject];
    }
}

- (void)setupDelegates {
    self.chatTableView.delegate = self;
    self.chatTableView.dataSource = self; // 添加数据源
    self.messageView.inputMessageField.delegate = self;
}

#pragma mark - UITableViewDataSource

- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    // 返回消息的数量
    return self.messages ? [self.messages count] : 0;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    ChatMessageCell *cell = [tableView dequeueReusableCellWithIdentifier:@"ChatMessageCell" forIndexPath:indexPath];
    // 根据索引路径配置单元格
    MessageModel *message = self.messages[indexPath.row];
    UIImage* sicon = [UIImage imageNamed:@"DeUseravatar"];

    [cell configureWithMessage:message iconSendImage:sicon iconReceiveImage:self.iconimage topicName:self.name options:self.options];

    //[cell layoutIfNeeded];
    return cell;
}

#pragma mark - UITableViewDelegate

- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
    MessageModel *message = self.messages[indexPath.row];
    return message.cellHeight > 0 ? message.cellHeight : 60.0;
}

