@implementation AdManager

+ (void)load {
    NSLog(@"load AdManager sharedManager");
}

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[AdManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        _isLaunching = NO;
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppFinishLaunching) name:UIApplicationDidFinishLaunchingNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppBecomeActive) name:UIApplicationDidBecomeActiveNotification object:nil];
        // 监听广告加载完成的通知
        [[NSNotificationCenter defaultCenter] addObserver:self
                                                 selector:@selector(handleSplashAdFinished)
                                                     name:@"SplashAdDidFinish"
                                                   object:nil];
    }
    return self;
}

#pragma mark - lifecycle observer

- (void)onAppFinishLaunching {
    [self handleAdsDataFeedback];
}

- (void)onAppBecomeActive {
    if (!_isLaunching) {
#if ENABLE_FEATURE_A && ENABLE_FEEDBACK
        [[InterstitialAd sharedManager] loadInterstitialAd];
#endif
    }
}

- (void)handleAdsDataFeedback {
    static dispatch_once_t onceToken;// 使用 static 的 dispatch_once_t 来保证代码块只执行一次，无论应用程序启动多少次。
    dispatch_once(&onceToken, ^{
        _isLaunching = YES;
        [self asyncInitializeIfPossibleAndNeeded];
    });
}

- (void)handleSplashAdFinished {
    self.isLaunching = NO;
}


#pragma mark - events

- (void)getAdsData {
    [NetworkManager.sharedManager afaceInitWithDeviceUUID:UserInfo.deviceUUID bundleId:UserInfo.bundleId systemVersion:UserInfo.systemVersion callback:^(id _Nullable json, NSError * _Nullable error) {
        if (error) {
            [[NSNotificationCenter defaultCenter] postNotificationName:@"SplashAdDidFinish" object:nil];
            return;
        }
        if (!json || json == [NSNull null] || ![json isKindOfClass:[NSDictionary class]]) {
            [[NSNotificationCenter defaultCenter] postNotificationName:@"SplashAdDidFinish" object:nil];
            return;
        }
        NSNumber *code = json[@"code"];
        NSString *message = json[@"message"];
        if (code && [code integerValue] == 200 && [message isEqualToString:@"success"]) {
            id data = [self safeValueForKey:@"data" fromDictionary:json];
            if ([data isKindOfClass:[NSDictionary class]]) {
                id adsData = [self safeValueForKey:@"ads" fromDictionary:data];
                if (adsData && [adsData isKindOfClass:[NSDictionary class]]) {
                    self.adModel = [AdModel modelWithJSON:adsData];
                    NSLog(@"adModel initialized successful");
                    NSLog(@"广告参数接收完成！");
                    [self handleAdsDataFeedback];
                    return;
                }
            }
        }
        [[NSNotificationCenter defaultCenter] postNotificationName:@"SplashAdDidFinish" object:nil];
    }];
}


- (id)safeValueForKey:(NSString *)key fromDictionary:(NSDictionary *)dict {
    id value = [dict objectForKey:key];
    if (value == [NSNull null] || value == nil) {
        return nil;
    }
    return value;
}



#pragma mark - GroMore AdSDKInit

- (void)asyncInitializeIfPossibleAndNeeded {

#if ENABLE_FEATURE_A && ENABLE_FEEDBACK
    /******************** 初始化穿山甲聚合SDK ********************/
    BUAdSDKConfiguration *configuration = [BUAdSDKConfiguration configuration];
    // 设置APPID
    configuration.appID = [AdManager sharedManager].adModel.ADSAppId;
    // 设置日志输出
    configuration.debugLog = @(0);
    // 设置使用聚合
    configuration.useMediation = YES;
    // 隐私合规配置
    // 是否禁止IDFA
    configuration.mediation.forbiddenIDFA = @(0);
    // 是否限制个性化广告
    configuration.mediation.limitPersonalAds = @(0);
    // 是否限制程序化广告
    configuration.mediation.limitProgrammaticAds = @(0);
    // 主题模式
    configuration.themeStatus = @(BUAdSDKThemeStatus_Normal);

    // 初始化
    [BUAdSDKManager startWithAsyncCompletionHandler:^(BOOL success, NSError *error) {
        if (success) {
            NSLog(@"广告SDK初始化成功");
            [SplashAd.sharedManager loadSplashAd];  // 加载开屏广告
        } else {
            NSLog(@"广告SDK初始化失败:%@", error.localizedDescription);
            // 即使广告初始化失败，也需要通知进入主界面
            [[NSNotificationCenter defaultCenter] postNotificationName:@"SplashAdDidFinish" object:nil];
        }
    }];
#endif

}


@end


