+ (NSString *)deviceUUID {
    NSError *error = nil;
    NSString *uuid = [SAMKeychain passwordForService:ABBridge_GetAppCodeName() account:WEBOX_ACCOUNT_UUID error:&error];
    if (!uuid || (error && error.code == errSecItemNotFound)) {
        CFUUIDRef uuidRef = CFUUIDCreate(kCFAllocatorDefault);
        CFStringRef strRef = CFUUIDCreateString(kCFAllocatorDefault, uuidRef);
